 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { SelectOption } from '@patternfly/react-core';
 6	
 7	import { getBooleanText } from '../../../../utils/utils';
 8	
 9	type YesNoDropdownProps = {
10	  setState: Dispatch<SetStateAction<boolean>>;
11	  state: boolean;
12	};
13	
14	const YesNoDropdown: FC<YesNoDropdownProps> = ({ setState, state }) => {
15	  const { t } = useKubevirtTranslation();
16	
17	  return (
18	    <FormPFSelect popperProps={{ width: '141px' }} selected={getBooleanText(state)}>
19	      <SelectOption key="yes-opt" onClick={() => setState(true)} value={t('Yes')}>
20	        {t('Yes')}
21	      </SelectOption>
22	      <SelectOption key="no-opt" onClick={() => setState(false)} value={t('No')}>
23	        {t('No')}
24	      </SelectOption>
25	    </FormPFSelect>
26	  );
27	};
28	
29	export default YesNoDropdown;

